while (true) {

  let t10Closed = getTurnoutState(10);
  let t11Closed = getTurnoutState(11);
  let t12Closed = getTurnoutState(12);
  let t13Closed = getTurnoutState(13);

  // Signal #135
  if (!t10Closed && t11Closed) {
    setSignalYellow(135);
  } else {
    setSignalRed(135);
  }

  // Signal #120
  if (t10Closed && t11Closed) {
    setSignalGreen(120);
  } else {
    setSignalRed(120);
  }

  // Signal #140
  if (!t11Closed) {
    setSignalYellow(140);
  } else {
    setSignalRed(140);
  }

  // Signal #145
  if (!t12Closed) {
    setSignalYellow(145);
  } else {
    setSignalRed(145);
  }

  // Signal #150
  if (t12Closed && t13Closed) {
    setSignalGreen(150);
  } else {
    setSignalRed(150);
  }

  // Signal #155
  if (t12Closed && !t13Closed) {
    setSignalYellow(155);
  } else {
    setSignalRed(155);
  }

  await sleep(500);
}
